.wrapper-exec-hero {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  --hero-ink: #0B0B0D;
  --hero-line: rgba(11,11,13,.18);
  container-type: inline-size;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}

/* ---- Hero band: yellow -> pink gradient, dark ink, restrained accent glow ---- */
.wrapper-exec-hero .hero {
  position: relative;
  isolation: isolate;
  overflow: hidden;
  border-radius: 16px;
  padding: 28px 28px 24px;
  background: linear-gradient(135deg, var(--accent), var(--accent-2));
  box-shadow:
    0 1px 0 rgba(255,255,255,.10) inset,
    0 14px 40px rgba(0,0,0,.55),
    0 0 64px -28px color-mix(in srgb, var(--accent, #FFD21E) 70%, transparent);
  color: var(--hero-ink);
}
.wrapper-exec-hero .hero::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: -1;
  pointer-events: none;
  background:
    radial-gradient(120% 90% at 0% 0%, rgba(255,255,255,.22), transparent 55%),
    radial-gradient(120% 120% at 100% 100%, rgba(11,11,13,.20), transparent 60%);
}

.wrapper-exec-hero .hero-head { position: relative; max-width: 70%; }

.wrapper-exec-hero .eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin: 0;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--hero-ink);
  opacity: .74;
}
.wrapper-exec-hero .eyebrow::before {
  content: "";
  width: 18px;
  height: 2px;
  border-radius: 2px;
  background: var(--hero-ink);
  opacity: .8;
}

.wrapper-exec-hero .title {
  margin: 10px 0 0;
  font: 800 30px/1.05 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  font-size: clamp(22px, 5.5cqi, 30px);
  letter-spacing: -.02em;
  color: var(--hero-ink);
  text-wrap: balance;
  overflow-wrap: anywhere;
}

.wrapper-exec-hero .subtitle {
  margin: 8px 0 0;
  font: 600 13px/1.45 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--hero-ink);
  opacity: .78;
  overflow-wrap: anywhere;
}

.wrapper-exec-hero .tiles {
  position: relative;
  margin-top: 24px;
  padding-top: 22px;
  border-top: 1px solid var(--hero-line);
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 14px;
}

.wrapper-exec-hero .tile {
  min-width: 0;
  border-radius: 14px;
  padding: 16px;
  background: rgba(11,11,13,.16);
  border: 1px solid rgba(11,11,13,.22);
  box-shadow: inset 0 1px 0 rgba(255,255,255,.14);
  -webkit-backdrop-filter: blur(2px);
  backdrop-filter: blur(2px);
  transition: transform .16s ease, background-color .16s ease, border-color .16s ease;
}
.wrapper-exec-hero .tile:hover {
  transform: translateY(-2px);
  background: rgba(11,11,13,.24);
  border-color: rgba(11,11,13,.34);
}

.wrapper-exec-hero .tile-label {
  display: flex;
  align-items: center;
  gap: 7px;
  margin: 0;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .12em;
  text-transform: uppercase;
  color: var(--hero-ink);
  opacity: .74;
}
.wrapper-exec-hero .tile-label::before {
  content: "";
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--hero-ink);
  opacity: .85;
  flex: none;
}

.wrapper-exec-hero .tile-value {
  margin: 10px 0 0;
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  font-size: clamp(21px, 5cqi, 26px);
  letter-spacing: -.01em;
  font-variant-numeric: tabular-nums;
  color: var(--hero-ink);
  overflow-wrap: anywhere;
}

.wrapper-exec-hero .tile-ctx {
  margin: 5px 0 0;
  font: 600 11px/1.35 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--hero-ink);
  opacity: .66;
  overflow-wrap: anywhere;
}

.wrapper-exec-hero :focus-visible {
  outline: 2px solid var(--hero-ink);
  outline-offset: 2px;
  border-radius: 10px;
}

@media (prefers-reduced-motion: reduce) {
  .wrapper-exec-hero .tile { transition: none; }
  .wrapper-exec-hero .tile:hover { transform: none; }
}

/* ---- Responsive: width-first container-query collapse ladder ---- */
/* Tiles size to the BLOCK's own inline width (cqi), not the viewport, so the
   band reflows correctly inside a narrow portal grid cell. 4 tiles -> clean
   2-up -> 1-up (3-up would orphan a single tile). */
@container (max-width: 780px) {
  .wrapper-exec-hero .hero { padding: 26px 24px 22px; }
  .wrapper-exec-hero .hero-head { max-width: 100%; }
  .wrapper-exec-hero .tiles { grid-template-columns: repeat(2, minmax(0, 1fr)); }
}

@container (max-width: 440px) {
  .wrapper-exec-hero .hero { padding: 22px 18px 18px; }
  .wrapper-exec-hero .tiles {
    grid-template-columns: 1fr;
    margin-top: 20px;
    padding-top: 18px;
    gap: 12px;
  }
}
